// App.jsx
function App() {
  return (
    <div>
      <h1>Hello, React!</h1>
      <p>Welcome to your first React component.</p>
    </div>
  );
}

export default App;

// JSX syntax
const element = <h1 className="title">Hello, {name}!</h1>;

// Compiled to
const element = React.createElement('h1', { className: 'title' }, 'Hello, ', name, '!');

// JSX rules:
// - Use camelCase for attributes (className, onClick)
// - Wrap multiple elements in fragments <>...</> or <div>...</div>
// - Embed JavaScript expressions with {}
// - Self-close tags like <img />

// Child component
function Greeting({ name, age }) {
  return (
    <div>
      <h2>Hello, {name}!</h2>
      <p>Age: {age}</p>
    </div>
  );
}

// Parent component
function App() {
  return (
    <div>
      <Greeting name="Alice" age={25} />
      <Greeting name="Bob" age={30} />
    </div>
  );
}

// Default props
function Button({ label = 'Click me', onClick }) {
  return <button onClick={onClick}>{label}</button>;
}

import { useState } from 'react';

function Counter() {
  const [count, setCount] = useState(0);

  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={() => setCount(count + 1)}>Increment</button>
      <button onClick={() => setCount(count - 1)}>Decrement</button>
    </div>
  );
}

// Multiple state variables
function UserForm() {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');

  return (
    <form>
      <input value={name} onChange={(e) => setName(e.target.value)} />
      <input value={email} onChange={(e) => setEmail(e.target.value)} />
    </form>
  );
}

import { useState, useEffect } from 'react';

function DataFetcher() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Runs after component mounts
    fetch('https://api.example.com/data')
      .then(res => res.json())
      .then(data => {
        setData(data);
        setLoading(false);
      });

    // Optional cleanup function
    return () => {
      // Cleanup subscriptions, timers, etc.
      console.log('Component unmounted');
    };
  }, []); // Empty array = run once

  if (loading) return <p>Loading...</p>;
  return <div>{JSON.stringify(data)}</div>;
}

function EventDemo() {
  const handleClick = (event) => {
    console.log('Button clicked!', event);
  };

  const handleInputChange = (e) => {
    console.log('Input value:', e.target.value);
  };

  const handleFormSubmit = (e) => {
    e.preventDefault();
    console.log('Form submitted!');
  };

  return (
    <div>
      <button onClick={handleClick}>Click Me</button>
      <input onChange={handleInputChange} placeholder="Type something..." />
      <form onSubmit={handleFormSubmit}>
        <button type="submit">Submit</button>
      </form>
    </div>
  );
}

function ConditionalDemo({ isLoggedIn, user }) {
  // If-else
  if (isLoggedIn) {
    return <h1>Welcome back, {user.name}!</h1>;
  }
  return <h1>Please log in</h1>;

  // Ternary operator
  return (
    <div>
      {isLoggedIn ? (
        <Dashboard user={user} />
      ) : (
        <LoginForm />
      )}
    </div>
  );

  // Logical && operator
  return (
    <div>
      {isLoggedIn && <WelcomeMessage />}
      {!isLoggedIn && <LoginPrompt />}
    </div>
  );
}

function TodoList({ todos }) {
  return (
    <ul>
      {todos.map(todo => (
        <li key={todo.id}>
          <input type="checkbox" checked={todo.completed} readOnly />
          {todo.text}
        </li>
      ))}
    </ul>
  );
}

// Filtered list
function FilteredList({ items, filterText }) {
  const filtered = items.filter(item =>
    item.name.toLowerCase().includes(filterText.toLowerCase())
  );

  return (
    <ul>
      {filtered.map(item => (
        <li key={item.id}>{item.name}</li>
      ))}
    </ul>
  );
}

// Parent to Child via props
function Parent() {
  const message = "Hello from parent";
  return <Child message={message} />;
}

function Child({ message }) {
  return <p>{message}</p>;
}

// Child to Parent via callbacks
function Parent() {
  const handleChildClick = (data) => {
    console.log('Data from child:', data);
  };
  return <Child onAction={handleChildClick} />;
}

function Child({ onAction }) {
  return (
    <button onClick={() => onAction('Child data')}>
      Send to Parent
    </button>
  );
}

// Sibling communication via shared parent
function Siblings() {
  const [sharedState, setSharedState] = useState('');
  return (
    <div>
      <SiblingA setSharedState={setSharedState} />
      <SiblingB sharedState={sharedState} />
    </div>
  );
}

